import{N as e,h as t,k as n,p as r,u as i}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as a}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const o=JSON.parse(`{"title":"Migrating Mappings","description":"Learn how to migrate your mod's obfuscation mappings.","frontmatter":{"title":"Migrating Mappings","description":"Learn how to migrate your mod's obfuscation mappings.","authors":["ArduFish","asiekierka","cassiancc","Daomephsta","deirn","Earthcomputer","florensie","Friendly-Banana","IMB11","jamierocks","JamiesWhiteShirt","liach","MildestToucan","modmuss50","natanfudge","Spinoscythe","UpcraftLP"],"authors-nogithub":["basil4088"],"resources":{"https://www.minecraft.net/en-us/article/removing-obfuscation-in-java-edition":"Removing Obfuscation in Java Edition - Minecraft.net","https://fabricmc.net/2025/10/31/obfuscation.html":"Removing Obfuscation from Fabric","../../404":"Tribute to Fabric Yarn (2016-2025)"},"files":[]},"headers":[],"relativePath":"develop/porting/mappings/index.md","filePath":"develop/porting/mappings/index.md","lastUpdated":1774467289000}`);var s={name:`develop/porting/mappings/index.md`};function c(a,o,s,c,l,u){let d=e(`ChoiceComponent`);return n(),i(`div`,null,[o[0]||=r(`<h1 id="h1" tabindex="-1">Migrating Mappings <a class="header-anchor" href="#h1" aria-label="Permalink to â€śMigrating Mappingsâ€ť">â€‹</a></h1><p>You may wish to migrate from Yarn to Mojang Mappings, especially if you are planning on <a href="#whats-going-on-with-mappings">updating your mod past the Mounts of Mayhem game drop</a>, or vice versa.</p><p>There are two ways to accomplish this: you can either use the <strong>Loom Gradle Plugin</strong>, or the <strong>Ravel IntelliJ IDEA Plugin</strong>.</p><p>Loom offers a semi-automated migration of the mappings through the <code>migrateMappings</code> task, but <strong>does not support migrating code written in Kotlin</strong>.</p><p>Ravel is a plugin for IntelliJ IDEA that adds a GUI dialog for migration. Unlike Loom however, Ravel also <strong>supports Kotlin</strong>. In addition, Ravel might perform better than Loom for more complex projects since it uses IDE to resolve changes.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>The Fabric API used Ravel to migrate from Yarn to Mojang Mappings. See <a href="https://github.com/FabricMC/fabric/pull/4960" target="_blank" rel="noreferrer">PR #4690 on the Fabric API repo</a>.</p></div><p>Neither option is perfect, and you still have to review the results and make manual fixes, especially if migrating Mixins.</p>`,7),t(d,{choices:[{name:`Loom Gradle Plugin`,href:`./loom`,icon:`simple-icons:gradle`,color:`#4DC9C0`},{name:`Ravel IntelliJ IDEA Plugin`,href:`./ravel`,icon:`simple-icons:intellijidea`,color:`#FE2857`}]}),o[1]||=r(`<h2 id="whats-going-on-with-mappings" tabindex="-1">What&#39;s Going On with Mappings? <a class="header-anchor" href="#whats-going-on-with-mappings" aria-label="Permalink to â€śWhat&#39;s Going On with Mappings?â€ť">â€‹</a></h2><p>Historically, Minecraft: Java Edition has made use of obfuscation, which led to the development of obfuscation maps that Fabric Loom uses for modding. There were two choices: either Fabric&#39;s own Yarn mappings, or the official Mojang mappings.</p><p>Mojang have recently announced <a href="https://www.minecraft.net/en-us/article/removing-obfuscation-in-java-edition" target="_blank" rel="noreferrer">they&#39;re removing code obfuscation from Minecraft: Java Edition</a>, and the Fabric Project followed up with <a href="https://fabricmc.net/2025/10/31/obfuscation.html" target="_blank" rel="noreferrer">its plan for handling this change</a>. If you plan to update your mod to this version, you will need to move to Mojang&#39;s obfuscation mappings first before updating.</p><h2 id="mappings" tabindex="-1">What Are Mappings? <a class="header-anchor" href="#mappings" aria-label="Permalink to â€śWhat Are Mappings?â€ť">â€‹</a></h2><p>Minecraft: Java Edition has been obfuscated since its release, which means that its code had human-friendly class names like <code>Creeper</code> replaced with gibberish like <code>brc</code>. In order to easily mod it, Fabric Loom makes use of obfuscation maps: references which translate obfuscated class names, such as <code>brc</code>, back to human-friendly names like <code>CreeperEntity</code>.</p><p>As a Fabric developer, you&#39;ll encounter three main sets of names:</p><ul><li><strong>Intermediary</strong>: The mapping set used by compiled Fabric mods; for example <code>brc</code> may become <code>class_1548</code>. The point behind Intermediary is offering a stable set of names across releases, as obfuscated class names change with each new version of Minecraft. This often allows mods built for one version to work on others, as long as the affected parts of the game haven&#39;t changed too much.</li><li><strong>Yarn</strong>: an open-source mapping set developed by Fabric for humans to write mods. Most Fabric mods used Yarn Mappings, as they were the default before 2025. An example mapping might be <code>CreeperEntity</code>.</li><li><strong>Mojang Mappings</strong>: The game&#39;s official obfuscation mappings, released by Mojang in 2019 to aid mod development. Notably, Mojang&#39;s obfuscation mappings lack parameter names and Javadocs, which is why some users also layer <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> over the official mappings. An example mapping might be <code>Creeper</code>.</li></ul><p>Minecraft 26.1 will be deobfuscated and include parameter names, so there won&#39;t be a need for any obfuscation mappings.</p>`,8)])}var l=a(s,[[`render`,c]]);export{o as __pageData,l as default};